// MARK: - Keychain Helper

class KeychainManager {
    
    static let shared = KeychainManager()
    private init() {}
    
    private let service = "com.myapp.authentication"
    private let account = "biometricAuthEnabled"
    private let authTokenAccount = "authToken"
    
    func setBiometricAuthEnabled(_ enabled: Bool) {
        let data = Data([enabled ? 1 : 0])
        save(data: data, forAccount: account)
    }
    
    func isBiometricAuthEnabled() -> Bool {
        guard let data = load(account: account), let firstByte = data.first else {
            return false
        }
        return firstByte == 1
    }
    
    func saveAuthToken(_ token: String) {
        guard let data = token.data(using: .utf8) else { return }
        save(data: data, forAccount: authTokenAccount)
    }
    
    func loadAuthToken() -> String? {
        guard let data = load(account: authTokenAccount) else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    func clearAll() {
        delete(account: account)
        delete(account: authTokenAccount)
    }
    
    private func save(data: Data, forAccount account: String) {
        delete(account: account)
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemAdd(query as CFDictionary, nil)
    }
    
    private func load(account: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        SecItemCopyMatching(query as CFDictionary, &result)
        return result as? Data
    }
    
    private func delete(account: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Biometric Authentication Manager

class BiometricAuthManager {
    
    static let shared = BiometricAuthManager()
    private init() {}
    
    enum BiometricType {
        case none
        case touchID
        case faceID
    }
    
    enum AuthenticationResult {
        case success
        case failure(Error)
        case cancelled
        case biometryNotAvailable
        case biometryNotEnrolled
        case biometryLockedOut
        case fallbackRequested
    }
    
    var biometricType: BiometricType {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        
        switch context.biometryType {
        case .touchID:
            return .touchID
        case .faceID:
            return .faceID
        case .opticID:
            return .none
        @unknown default:
            return .none
        }
    }
    
    var biometricTypeString: String {
        switch biometricType {
        case .faceID:
            return "Face ID"
        case .touchID:
            return "Touch ID"
        case .none:
            return "Biometric Authentication"
        }
    }
    
    var isBiometricAvailable: Bool {
        let context = LAContext()
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    func authenticate(reason: String? = nil, completion: @escaping (AuthenticationResult) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Cancel"
        context.localizedFallbackTitle = "Use Password"
        
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            if let laError = error as? LAError {
                switch laError.code {
                case .biometryNotAvailable:
                    completion(.biometryNotAvailable)
                case .biometryNotEnrolled:
                    completion(.biometryNotEnrolled)
                case .biometryLockout:
                    // Fall back to device passcode to reset biometry lockout
                    authenticateWithDevicePasscode(context: context, reason: reason, completion: completion)
                default:
                    completion(.failure(laError))
                }
            } else {
                completion(.biometryNotAvailable)
            }
            return
        }
        
        let authReason = reason ?? "Authenticate to access your account"
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: authReason) { success, error in
            DispatchQueue.main.async {
                if success {
                    completion(.success)
                } else if let laError = error as? LAError {
                    switch laError.code {
                    case .userCancel:
                        completion(.cancelled)
                    case .userFallback:
                        completion(.fallbackRequested)
                    case .biometryLockout:
                        completion(.biometryLockedOut)
                    case .authenticationFailed:
                        completion(.failure(laError))
                    default:
                        completion(.failure(laError))
                    }
                } else if let error = error {
                    completion(.failure(error))
                }
            }
        }
    }
    
    private func authenticateWithDevicePasscode(context: LAContext, reason: String?, completion: @escaping (AuthenticationResult) -> Void) {
        let authReason = reason ?? "Authenticate to access your account"
        
        context.evaluatePolicy(.deviceOwnerAuthentication, localizedReason: authReason) { success, error in
            DispatchQueue.main.async {
                if success {
                    completion(.success)
                } else if let laError = error as? LAError {
                    switch laError.code {
                    case .userCancel:
                        completion(.cancelled)
                    default:
                        completion(.failure(laError))
                    }
                } else if let error = error {
                    completion(.failure(error))
                }
            }
        }
    }
}

// MARK: - Authentication Session Manager

class AuthSessionManager {
    
    static let shared = AuthSessionManager()
    private init() {}
    
    private(set) var isAuthenticated: Bool = false
    
    var shouldShowBiometricLogin: Bool {
        return KeychainManager.shared.isBiometricAuthEnabled() &&
               KeychainManager.shared.loadAuthToken() != nil &&
               BiometricAuthManager.shared.isBiometricAvailable
    }
    
    func markAuthenticated(token: String) {
        isAuthenticated = true
        KeychainManager.shared.saveAuthToken(token)
    }
    
    func enableBiometricAuth() {
        KeychainManager.shared.setBiometricAuthEnabled(true)
    }
    
    func disableBiometricAuth() {
        KeychainManager.shared.setBiometricAuthEnabled(false)
    }
    
    func logout() {
        isAuthenticated = false
        KeychainManager.shared.clearAll()
    }
    
    func authenticateWithBiometrics(completion: @escaping (Bool) -> Void) {
        BiometricAuthManager.shared.authenticate { [weak self] result in
            switch result {
            case .success:
                self?.isAuthenticated = true
                completion(true)
            default:
                completion(false)
            }
        }
    }
}

