// MARK: - Main View Controller (Post-Login)

class MainViewController: UIViewController {
    
    private let welcomeLabel: UILabel = {
        let label = UILabel()
        label.text = "You're signed in! 🎉"
        label.font = .systemFont(ofSize: 24, weight: .bold)
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let biometricToggleLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 16, weight: .regular)
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let biometricSwitch: UISwitch = {
        let toggle = UISwitch()
        toggle.translatesAutoresizingMaskIntoConstraints = false
        return toggle
    }()
    
    private let logoutButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Sign Out", for: .normal)
        button.titleLabel?.font = .systemFont(ofSize: 18, weight: .semibold)
        button.setTitleColor(.systemRed, for: .normal)
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        navigationItem.title = "Home"
        navigationItem.hidesBackButton = true
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        
        let biometricName = BiometricAuthManager.shared.biometricTypeString
        biometricToggleLabel.text = "Enable \(biometricName)"
        biometricSwitch.isOn = KeychainManager.shared.isBiometricAuthEnabled()
        biometricSwitch.addTarget(self, action: #selector(biometricToggleChanged), for: .valueChanged)
        
        let toggleStack = UIStackView(arrangedSubviews: [biometricToggleLabel, biometricSwitch])
        toggleStack.axis = .horizontal
        toggleStack.spacing = 12
        toggleStack.translatesAutoresizingMaskIntoConstraints = false
        
        // Hide toggle if biometric not available
        toggleStack.isHidden = !BiometricAuthManager.shared.isBiometricAvailable
        
        view.addSubview(welcomeLabel)
        view.addSubview(toggleStack)
        view.addSubview(logoutButton)
        
        NSLayoutConstraint.activate([
            welcomeLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            welcomeLabel.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -60),
            
            toggleStack.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            toggleStack.topAnchor.constraint(equalTo: welcomeLabel.bottomAnchor, constant: 40),
            
            logoutButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            logoutButton.topAnchor.constraint(equalTo: toggleStack.bottomAnchor, constant: 40)
        ])
        
        logoutButton.addTarget(self, action: #selector(logoutTapped), for: .touchUpInside)
    }
    
    @objc private func biometricToggleChanged() {
        if biometricSwitch.isOn {
            // Verify identity before enabling biometric auth
            BiometricAuthManager.shared.authenticate(
                reason: "Verify your identity to enable \(BiometricAuthManager.shared.biometricTypeString)"
            ) { [weak self] result in
                switch result {
                case .success:
                    AuthSessionManager.shared.enableBiometricAuth()
                default:
                    self?.biometricSwitch.setOn(false, animated: true)
                }
            }
        } else {
            AuthSessionManager.shared.disableBiometricAuth()
        }
    }
    
    @objc private func logoutTapped() {
        let alert = UIAlertController(
            title: "Sign Out",
            message: "Are you sure you want to sign out?",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Sign Out", style: .destructive) { [weak self] _ in
            AuthSessionManager.shared.logout()
            self?.navigateToLogin()
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
    
    private func navigateToLogin() {
        let loginVC = LoginViewController()
        
        if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
           let window = windowScene.windows.first {
            window.rootViewController = loginVC
            UIView.transition(with: window, duration: 0.3, options: .transitionCrossDissolve, animations: nil)
        }
    }
}

// MARK: - App Flow Coordinator

class AppFlowCoordinator {
    
    static let shared = AppFlowCoordinator()
    private init() {}
    
    func determineInitialViewController() -> UIViewController {
        if AuthSessionManager.shared.shouldShowBiometricLogin {
            // User has biometric enabled and has a stored token
            // Show login screen which will automatically trigger biometric auth
            return LoginViewController()
        } else if KeychainManager.shared.loadAuthToken() != nil {
            // User has a token but no biometric - could auto-login or show login
            // For security, we'll still show login but you could auto-authenticate here
            return LoginViewController()
        } else {
            // Fresh user, show login
            return LoginViewController()
        }
    }
}

// MARK: - SceneDelegate Integration

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        
        window = UIWindow(windowScene: windowScene)
        
        let initialVC = AppFlowCoordinator.shared.determineInitialViewController()
        
        if initialVC is MainViewController {
            window?.rootViewController = UINavigationController(rootViewController: initialVC)
        } else {
            window?.rootViewController = initialVC
        }
        
        window?.makeKeyAndVisible()
    }
    
    func sceneDidBecomeActive(_ scene: UIScene) {
        // Optional: Re-authenticate when app becomes active after being in background
    }
    
    func sceneWillResignActive(_ scene: UIScene) {
        // Optional: Add a privacy overlay when app goes to background
    }
}

